// // This module is designed to compare two 16-bit input values A and B.
// It outputs three signals: A_gt_B (low if A > B), A_lt_B (low if A < B), and A_eq_B (low if A == B).

module Comparator_16bit(
    input [15:0] A,
    input [15:0] B,
    output reg A_gt_B,
    output reg A_lt_B,
    output reg A_eq_B
);

// Combinational logic for comparison
always @(*) begin
    A_gt_B = (A > B);
    A_lt_B = (A < B);
    A_eq_B = (A == B);
end

endmodule
